  malphite: { diff: "FAVOURED", tone: "#3ddc97", tldr: "Poke + blind \u2014 vault his R, blind his autos.", breakdown: "Auto-Q poke his weak early, blind his autos, and E-vault out of his R.", dos: ["Auto-Q poke his early", "Blind (E) his autos", "E-vault out of his R"], donts: ["Auto-trade his passive", "Eat his R knockup", "Get stuck in melee"], key: { slot: "R", name: "Unstoppable Force", cd: "130s", note: "Un-dodgeable burst. Vault/dodge it.", winT: "ULT DOWN", winS: "Vault-blind + R him." }, hold: "Hold E to vault out of his R engage \u2014 dodge the knockup; blind his passive autos.", tip: "Auto-Q poke his weak early, blind his autos, and E-vault out of his R.", win: "Poke + blind, vault his R." },
