  ornn: { diff: "EVEN", tone: "#e8b84b", tldr: "Poke his early \u2014 build pen, dodge his Q.", breakdown: "Both scale. Auto-Q poke his weak early, build pen, and dodge his Q wall-knockup.", dos: ["Auto-Q poke his early", "Build armor pen", "Dodge his Q knockup"], donts: ["Stand near walls for his Q", "Get brittle-procced", "Get stuck in melee"], key: { slot: "Q", name: "Volcanic Rupture", cd: "10s", note: "Wall-knockup setup. Dodge it.", winT: "RUPTURE DOWN", winS: "Vault-blind + R him." }, hold: "Hold E to vault out of his brittle combo \u2014 deny the knockup setup.", tip: "Both scale \u2014 auto-Q poke his early, build pen, and dodge his Q.", win: "Poke his early, vault his Q." },
  poppy: { diff: "EVEN", tone: "#e8b84b", tldr: "Poke + kite \u2014 vault her engage, dodge her E.", breakdown: "Auto-Q poke from range, E-vault out of her engage, and dodge her E wall-stun.", dos: ["Auto-Q poke from range", "E-vault out of her engage", "Dodge her E wall-stun"], donts: ["Get E-wall-stunned", "Get R-knocked mid-combo", "Get stuck in melee"], key: { slot: "E", name: "Heroic Charge", cd: "14s", note: "Wall-pin stun. Dodge it.", winT: "CHARGE DOWN", winS: "Vault-blind + R her." }, hold: "Hold E to vault out of her engage \u2014 deny her E before she pins you.", tip: "Auto-Q poke from range, E-vault out of her engage, and dodge her E wall-stun.", win: "Poke + kite, vault her engage." },
