  zac: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 poke + kite, vault his E, anti-heal.", breakdown: "Build MR, auto-Q poke from range, E-vault out of his E slingshot, and anti-heal his sustain.", dos: ["Build MR", "Auto-Q poke from range", "Anti-heal his sustain"], donts: ["Let him eat blobs", "Get E-knocked-up", "Get stuck in melee"], key: { slot: "E", name: "Elastic Slingshot", cd: "16s", note: "His engage. Vault/dodge it.", winT: "SLINGSHOT DOWN", winS: "Vault-blind + R him." }, hold: "Hold E to vault out of his E slingshot \u2014 build MR; poke and anti-heal his sustain.", tip: "Build MR, auto-Q poke from range, E-vault out of his E, and anti-heal his sustain.", win: "Build MR and poke + kite him." },
