  akali: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 poke off shroud, blind her all-in.", breakdown: "Build MR, auto-Q poke her off her shroud, and blind her all-in autos.", dos: ["Build MR", "Auto-Q poke off her shroud", "Blind (E) her all-in"], donts: ["Fight her in the shroud", "Get Q-poked down", "Get stuck in melee"], key: { slot: "W", name: "Twilight Shroud", cd: "18s", note: "Untargetable inside. Poke when down.", winT: "SHROUD DOWN", winS: "Vault-blind + R her." }, hold: "Hold E to vault + blind her all-in \u2014 deny her combo autos; poke her off the shroud.", tip: "Build MR, auto-Q poke her off her shroud, and blind her all-in.", win: "Build MR, poke her off shroud." },
