  gangplank: { diff: "EVEN", tone: "#e8b84b", tldr: "Poke war \u2014 pop his barrels, blind his autos.", breakdown: "Pop his barrels, win the auto-Q poke war, and blind his autos.", dos: ["Pop his barrels", "Win the poke war", "Blind (E) his autos"], donts: ["Eat a full barrel chain", "Let him free-scale", "Get stuck in melee"], key: { slot: "E", name: "Powder Kegs", cd: "18s", note: "Pop barrels to deny poke + gold.", winT: "BARRELS CLEARED", winS: "Vault-blind + R him." }, hold: "Hold E to vault + blind him as he steps to a barrel \u2014 deny his autos and win the poke war.", tip: "Pop his barrels, win the auto-Q poke war, and blind his autos.", win: "Win the poke war, pop his barrels." },
  gnar: { diff: "EVEN", tone: "#e8b84b", tldr: "Poke mini \u2014 vault Mega, win the poke war.", breakdown: "Auto-Q poke mini Gnar, E-vault out of his Mega all-in, and win the poke war.", dos: ["Auto-Q poke mini Gnar", "E-vault out of his Mega all-in", "Win the poke war"], donts: ["Get kited in mini form", "Fight Mega\u2019s all-in raw", "Get stuck in melee"], key: { slot: "R", name: "GNAR! (Mega Stun)", cd: "90s", note: "His Mega all-in. Vault it.", winT: "MINI FORM", winS: "Vault-blind + R him." }, hold: "Hold E to vault out of his Mega all-in \u2014 deny his GNAR! engage; poke mini Gnar.", tip: "Auto-Q poke mini Gnar, E-vault out of his Mega all-in, and win the poke war.", win: "Poke mini, vault Mega." },
  heimerdinger: { diff: "TRICKY", tone: "#ff8b3d", tldr: "His turrets out-poke you \u2014 build MR, vault onto him.", breakdown: "Heimer\u2019s turrets out-poke you. Build MR, E-vault onto him off his nest, and blind his autos.", dos: ["Build MR", "E-vault onto him off his nest", "Blind (E) his autos"], donts: ["Dive a full nest raw", "Eat his E stun", "Poke-war into turrets"], key: { slot: "E", name: "CH-2 Grenade (Stun)", cd: "11s", note: "His self-peel stun. Dodge it.", winT: "GRENADE DOWN", winS: "Vault-blind + R him." }, hold: "Hold E to vault onto him off his nest \u2014 separate him from turrets, then blind + all-in.", tip: "Build MR and E-vault onto him off his nest \u2014 blind his autos and all-in him off his turrets.", win: "Build MR and vault onto him." },
