  kennen: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 poke war, blind his combo.", breakdown: "Build MR, win the auto-Q poke war, and blind his combo autos.", dos: ["Build MR", "Win the poke war", "Blind (E) his combo"], donts: ["Eat free Q pokes", "Get triple-stunned", "Fight into his R"], key: { slot: "E", name: "Lightning Rush", cd: "10s", note: "His escape. All-in when it\u2019s down.", winT: "E DOWN", winS: "Vault-blind + R him." }, hold: "Hold E to vault + blind his combo \u2014 deny his stun-stack autos.", tip: "Build MR, win the auto-Q poke war, and blind his combo autos.", win: "Build MR, win the poke war." },
  quinn: { diff: "MIRROR", tone: "#e8b84b", tldr: "Quinn mirror \u2014 whoever wins the auto-poke war and blinds first wins.", breakdown: "Pure Quinn mirror: it\u2019s an auto-poke and blind race. Whoever out-pokes and blinds the other\u2019s autos first wins.", dos: ["Win the auto-poke war", "Blind her autos first", "Vault to dodge her engage"], donts: ["Get blinded first", "Eat her vault-blind", "Fall behind in farm"], key: { slot: "E", name: "Vault (Dash/Blind)", cd: "11s", note: "Whoever blinds + out-pokes first wins.", winT: "VAULT DOWN", winS: "Vault-blind + R her." }, hold: "Hold E to vault + blind first \u2014 whoever out-pokes and blinds the other\u2019s autos first wins.", tip: "It\u2019s an auto-poke and blind mirror \u2014 win the poke war and blind her autos first.", win: "Win the poke war and blind first." },
  rumble: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 poke war, vault his engage, dodge R.", breakdown: "Build MR, win the auto-Q poke war, E-vault out of his engage, and dodge his R line.", dos: ["Build MR", "Win the poke war", "Dodge his R line"], donts: ["Extend into his danger-zone Q", "Stand in his R line", "Fight in his flamespitter"], key: { slot: "W", name: "Scrap Shield", cd: "6s", note: "Bait it, then commit.", winT: "SHIELD DOWN", winS: "Vault-blind + R him." }, hold: "Hold E to vault out of his engage \u2014 build MR; win the poke war and dodge his R.", tip: "Build MR, win the auto-Q poke war, E-vault out of his engage, and dodge his Equalizer.", win: "Build MR, win the poke war." },
  singed: { diff: "EVEN", tone: "#e8b84b", tldr: "Don\u2019t chase poison \u2014 poke from range, vault his fling.", breakdown: "Never chase through poison. Auto-Q poke from range, and E-vault out when he commits a fling.", dos: ["Auto-Q poke from range", "E-vault out of his fling", "Punish his proxy waves"], donts: ["Chase through his Q poison", "Get E-flipped into goo", "Get stuck in melee"], key: { slot: "E", name: "Fling", cd: "14s", note: "His flip. Vault/dodge it.", winT: "FLING DOWN", winS: "Vault-blind + R him." }, hold: "Hold E to vault out when he commits a fling \u2014 deny the flip and punish him.", tip: "Don\u2019t chase his poison \u2014 auto-Q poke from range and E-vault out of his fling.", win: "Poke + kite, vault his fling." },
  swain: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 poke war, vault his E root.", breakdown: "Build MR, win the auto-Q poke war, E-vault out of his E root, and anti-heal his R drain.", dos: ["Build MR + anti-heal", "Win the poke war", "E-vault out of his E root"], donts: ["Fight into his R drain", "Get E-rooted", "Get stuck in melee"], key: { slot: "R", name: "Demonic Ascension", cd: "100s", note: "His drain. Poke when it\u2019s down.", winT: "ASCENSION DOWN", winS: "Vault-blind + R him." }, hold: "Hold E to vault out of his E root \u2014 build MR; win the poke war.", tip: "Build MR, win the auto-Q poke war, E-vault out of his E root, and anti-heal his R drain.", win: "Build MR, win the poke war." },
