  vladimir: { diff: "EVEN", tone: "#e8b84b", tldr: "Bully him early \u2014 build MR, poke, bait pool.", breakdown: "Vlad is weak early. Build MR, auto-Q poke and bully him, and bait his pool.", dos: ["Auto-Q poke and bully early", "Build MR + anti-heal", "Bait his pool"], donts: ["Let him pool your combo", "Stack pure HP vs %damage", "Let him free-scale"], key: { slot: "W", name: "Sanguine Pool", cd: "22s", note: "Dodges your combo. Bait it.", winT: "POOL DOWN", winS: "Vault-blind + R him." }, hold: "Hold your R \u2014 bait his pool with poke first, then vault-blind + R when it\u2019s down.", tip: "He\u2019s weak early \u2014 auto-Q poke and bully him, bait his pool, and all-in when it\u2019s down.", win: "Bully him early and bait his pool." },
