  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"EVEN","tone":"#e8b84b","tldr":"Weather the poke — blind his Heroic Swing and kite the all-in apart.","breakdown":"Akshan plays around Heroic Swing. AA-mark weaving wins every short trade, Q-blind erases his Heroic Swing window, and R roams print the rest of the map. Doran’s Shield blunts the poke war.","dos":["Harass with passive marks","Q-blind his Heroic Swing trade","Vault out and re-kite"],"donts":["Vault INTO his engage","Burn Q off-trade","Stay past your kite range"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Blind + vault re-kite."},"win":"Blind his Heroic Swing and kite the all-in apart."},
  cassiopeia: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — blind his Miasma and kite the all-in apart.","breakdown":"Cassiopeia plays around Miasma. AA-mark weaving wins every short trade, Q-blind erases his Miasma window, and R roams print the rest of the map. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["Harass with passive marks","Q-blind his Miasma trade","Vault out and re-kite"],"donts":["Vault INTO his engage","Burn Q off-trade","Stay past your kite range"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"Blind + vault re-kite."},"win":"Blind his Miasma and kite the all-in apart."},
  galio: {"diff":"EVEN","tone":"#e8b84b","tldr":"Bait his key tool — blind his Justice Punch and kite the all-in apart.","breakdown":"Galio plays around Justice Punch. AA-mark weaving wins every short trade, Q-blind erases his Justice Punch window, and R roams print the rest of the map. Take Mercs / MR shard — his damage is magic.","dos":["Harass with passive marks","Q-blind his Justice Punch trade","Vault out and re-kite"],"donts":["Vault INTO his engage","Burn Q off-trade","Stay past your kite range"],"key":{"slot":"E","name":"Justice Punch","cd":"13s","note":"His dash + knockup engage. Punish him when it's down.","winT":"JUSTICE PUNCH DOWN","winS":"Blind + vault re-kite."},"win":"Blind his Justice Punch and kite the all-in apart."},
